// CORS Preflight abfangen
const method = $input.first().json.headers?.['method'] || $input.first().json.method || '';
if (method === 'OPTIONS') {
  return [{ json: { cors: true } }];
}

const body = $input.first().json.body || {};
const stationId = body.stationId || '';
const startDate = body.startDate || '';
const endDate = body.endDate || '';

if (!stationId || !startDate || !endDate) {
  return [{ json: { error: 'Parameter fehlen: stationId, startDate, endDate erforderlich', cors: false } }];
}

return [{ json: { stationId, startDate, endDate, cors: false } }];

const authResponse = $input.first().json;
const token = authResponse._id;
const params = $('Parameter validieren').first().json;
return [{ json: { token, stationId: params.stationId, startDate: params.startDate, endDate: params.endDate } }];

// Fahrzeug-IDs sammeln (API liefert nur active=true)
const vehicleItems = $('Fahrzeuge am Standort').all().map(i => i.json);
let vehicles = vehicleItems;
if (vehicleItems.length === 1 && Array.isArray(vehicleItems[0])) vehicles = vehicleItems[0];

const params = $('Token + Parameter').first().json;
const vehicleIds = vehicles.map(v => v._id).filter(Boolean);

return [{ json: { token: params.token, stationId: params.stationId, startDate: params.startDate, endDate: params.endDate, vehicleIds, totalVehicles: vehicleIds.length } }];

const bookingItems = $('Buchungen im Zeitraum').all().map(i => i.json);
let bookings = bookingItems;
if (bookingItems.length === 1 && Array.isArray(bookingItems[0])) bookings = bookingItems[0];

const params = $('Fahrzeuge auswerten').first().json;
const vehicleIds = params.vehicleIds || [];

// Gebuchte Fahrzeug-IDs die zu diesem Standort gehören
const bookedIds = new Set();
bookings.forEach(b => {
  if (b.vehicleId && vehicleIds.includes(b.vehicleId)) {
    bookedIds.add(b.vehicleId);
  }
});

const availableCount = vehicleIds.length - bookedIds.size;

return [{ json: {
  available: availableCount > 0,
  availableCount: Math.max(0, availableCount),
  totalAtStation: params.totalVehicles,
  stationId: params.stationId,
  startDate: params.startDate,
  endDate: params.endDate
} }];
